import sys
import itertools

class Solution:
    def solve(self) -> bool:
        for line in sys.stdin:
            self.board = [list(map(str, line.strip().split())) for line in sys.stdin]
            print(self.isValidSudoku(self.board))

    def isValidSudoku(self, board) -> bool:
        for i in range(9):
            row = board[i]
            if len(set(row)) != 9 or any(cell not in '123456789. ' for cell in row):
                return False

            for j in range(9):
                col = [board[x][j] for x in range(9)]
                if len(set(col)) != 9 or any(cell not in '123456789. ' for cell in col):
                    return False


        for k in range(3):
            for l in range(3):
                block = [board[x][y] for x in range(k*3, (k+1)*3) for y in range(l*3, (l+1)*3)]
                if len(set(block)) != 9 or any(cell not in '123456789. ' for cell in block):
                    return False

        return True

if __name__ == '__main__':
    solution = Solution()
    solution.solve()

