#include <iostream>
#include <vector>
#include <set>

using namespace std;

class Solution {
public:
bool isValidSudoku(vector<vector<char>>& board);

};

bool Solution::isValidSudoku(vector<vector<char>>& board) {
    for (int i = 0; i < 9; i++) {
        set<char> row, col;
        for (int j = 0; j < 9; j++) {
            row.insert(board[i][j]);
            col.insert(board[j][i]);
        }
        if (row.size() != 9 || col.size() != 9) {
            return false;
        }
    }
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            set<char> block;
            for (int k = i*3; k < (i+1)*3; k++) {
                for (int l = j*3; l < (j+1)*3; l++) {
                    block.insert(board[k][l]);
                }
            }
            if (block.size() != 9) {
                return false;
            }
        }
    }
    return true;
}

int main() {
    vector<vector<char>> board(9, vector<char>(9));
    for (int i = 0; i < 9; i++) {
        for (int j = 0; j < 9; j++) {
            cin >> board[i][j];
        }
    }
    Solution solution;
    cout << solution.isValidSudoku(board) << endl;
    return 0;
}
